import React, { useEffect, useState } from "react";

function App() {
  const [incidents, setIncidents] = useState([]);
  const [component, setComponent] = useState("");
  const [message, setMessage] = useState("");
  const [selectedIncident, setSelectedIncident] = useState(null);
  const [showRCAForm, setShowRCAForm] = useState(null);
  const [rcaData, setRcaData] = useState({ root: "", fix: "" });
  const [view, setView] = useState("ACTIVE");

  // Fetch incidents
  const fetchIncidents = async () => {
    const res = await fetch("http://127.0.0.1:8000/incidents");
    const data = await res.json();

    const priority = { P0: 1, P1: 2, P2: 3 };

    const sorted = data.sort(
      (a, b) => priority[a.severity] - priority[b.severity]
    );

    setIncidents(sorted);
  };

  useEffect(() => {
    fetchIncidents();
    const interval = setInterval(fetchIncidents, 3000);
    return () => clearInterval(interval);
  }, []);

  // Status flow helper
  const getStatusSteps = (current) => {
    const steps = ["OPEN", "INVESTIGATING", "RESOLVED", "CLOSED"];
    return steps.map((step) => ({
      name: step,
      active: step === current,
      completed: steps.indexOf(step) < steps.indexOf(current),
    }));
  };

  // Send signal
  const sendSignal = async () => {
    if (!component || !message) {
      alert("⚠️ Enter Component & Message");
      return;
    }

    await fetch(
      `http://127.0.0.1:8000/ingest?component_id=${component}&message=${message}`,
      { method: "POST" }
    );

    setComponent("");
    setMessage("");
    fetchIncidents();
  };

  const updateStatus = async (id, status) => {
    await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=${status}`,
      { method: "PUT" }
    );
    fetchIncidents();
  };

  const closeIncident = async (id) => {
    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=CLOSED`,
      { method: "PUT" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert(data.detail);
    }

    fetchIncidents();
  };

  const submitRCA = async (id) => {
    await fetch(
      `http://127.0.0.1:8000/incident/${id}/rca?root_cause=${rcaData.root}&fix=${rcaData.fix}`,
      { method: "POST" }
    );

    setShowRCAForm(null);
    setRcaData({ root: "", fix: "" });
    fetchIncidents();
  };

  const filteredIncidents =
    view === "ACTIVE"
      ? incidents.filter((i) => i.status !== "CLOSED")
      : incidents.filter((i) => i.status === "CLOSED");

  return (
    <div
      style={{
        padding: "20px",
        fontFamily: "Arial",
        background: "#f5f7fa",
        minHeight: "100vh",
      }}
    >
      <h1 style={{ color: "#2c3e50" }}>🚨 Incident Dashboard</h1>

      {/* Input */}
      <div
        style={{
          background: "#fff",
          padding: "15px",
          borderRadius: "8px",
          marginBottom: "15px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.1)",
        }}
      >
        <input
          placeholder="Component"
          value={component}
          onChange={(e) => setComponent(e.target.value)}
        />
        <input
          placeholder="Message"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          style={{ marginLeft: "10px" }}
        />
        <button
          onClick={sendSignal}
          style={{
            marginLeft: "10px",
            background: "#3498db",
            color: "#fff",
            border: "none",
            padding: "6px 12px",
            borderRadius: "5px",
          }}
        >
          Send
        </button>
      </div>

      {/* Toggle */}
      <div style={{ marginBottom: "10px" }}>
        <button onClick={() => setView("ACTIVE")}>Active</button>
        <button onClick={() => setView("CLOSED")} style={{ marginLeft: "10px" }}>
          Closed
        </button>
      </div>

      <h2>{view} Incidents ({filteredIncidents.length})</h2>

      {filteredIncidents.map((inc) => (
        <div
          key={inc.id}
          onClick={() =>
            setSelectedIncident(selectedIncident === inc.id ? null : inc.id)
          }
          style={{
            background: "#fff",
            margin: "10px 0",
            padding: "15px",
            borderRadius: "8px",
            boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
            cursor: "pointer",
          }}
        >
          <h3>Incident #{inc.id}</h3>

          <p><b>Component:</b> {inc.component_id}</p>

          <p>
            <b>Severity:</b>{" "}
            <span
              style={{
                background:
                  inc.severity === "P0"
                    ? "red"
                    : inc.severity === "P1"
                    ? "orange"
                    : "gray",
                color: "#fff",
                padding: "4px 8px",
                borderRadius: "5px",
              }}
            >
              {inc.severity}
            </span>
          </p>

          {/* 🔥 STATUS PROGRESS BAR */}
          <div style={{ display: "flex", marginBottom: "10px" }}>
            {getStatusSteps(inc.status).map((step, i) => (
              <div
                key={i}
                style={{
                  padding: "5px 10px",
                  marginRight: "5px",
                  borderRadius: "5px",
                  fontSize: "12px",
                  backgroundColor: step.active
                    ? "#3498db"
                    : step.completed
                    ? "#2ecc71"
                    : "#ddd",
                  color: "#fff",
                }}
              >
                {step.name}
              </div>
            ))}
          </div>

          <p><b>Signals:</b> {inc.signals.length}</p>

          {/* Expand signals */}
          {selectedIncident === inc.id && (
            <div>
              <h4>Signals</h4>
              {inc.signals.map((s, i) => (
                <div key={i}>
                  {s.message} - {new Date(s.timestamp).toLocaleString()}
                </div>
              ))}
            </div>
          )}

          {/* Buttons */}
          <div style={{ marginTop: "10px" }}>
            <button
              disabled={inc.status !== "OPEN"}
              onClick={(e) => {
                e.stopPropagation();
                updateStatus(inc.id, "INVESTIGATING");
              }}
            >
              Investigate
            </button>

            <button
              disabled={inc.status !== "INVESTIGATING"}
              onClick={(e) => {
                e.stopPropagation();
                updateStatus(inc.id, "RESOLVED");
              }}
            >
              Resolve
            </button>

            <button
              disabled={inc.status !== "RESOLVED" || inc.rca}
              onClick={(e) => {
                e.stopPropagation();
                setShowRCAForm(inc.id);
              }}
            >
              Add RCA
            </button>

            <button
              disabled={inc.status !== "RESOLVED" || !inc.rca}
              onClick={(e) => {
                e.stopPropagation();
                closeIncident(inc.id);
              }}
            >
              Close
            </button>
          </div>

          {/* RCA Form */}
          {showRCAForm === inc.id && (
            <div onClick={(e) => e.stopPropagation()}>
              <input
                placeholder="Root cause"
                value={rcaData.root}
                onChange={(e) =>
                  setRcaData({ ...rcaData, root: e.target.value })
                }
              />
              <textarea
                placeholder="Fix"
                value={rcaData.fix}
                onChange={(e) =>
                  setRcaData({ ...rcaData, fix: e.target.value })
                }
              />
              <button onClick={() => submitRCA(inc.id)}>Submit</button>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

export default App;
